import torch
from torchvision import models, transforms
from torch.utils.data import DataLoader, Dataset
from PIL import Image

# Step 1: Download a pretrained model
model_url = 'https://download.pytorch.org/models/resnet18-5c106c9d.pth'
model = models.resnet18(pretrained=True)
model.load_state_dict(torch.hub.load_state_dict_from_url(model_url))

# Step 2: Fine-tune the model on a custom dataset
class CustomDataset(Dataset):
    def __init__(self, image_paths, labels, transform=None):
        self.image_paths = image_paths
        self.labels = labels
        self.transform = transform

    def __len__(self):
        return len(self.image_paths)

    def __getitem__(self, idx):
        image_path = self.image_paths[idx]
        label = self.labels[idx]
        image = Image.open(image_path).convert('RGB')
        if self.transform:
            image = self.transform(image)
        return image, label

# Define transformations
transform = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
])

# Load custom dataset
image_paths = ['path/to/image1.jpg', 'path/to/image2.jpg']  # List of image paths
labels = [0, 1]  # Corresponding labels
dataset = CustomDataset(image_paths, labels, transform=transform)
dataloader = DataLoader(dataset, batch_size=4, shuffle=True)

# Step 3: Fine-tune the model
criterion = torch.nn.CrossEntropyLoss()
optimizer = torch.optim.SGD(model.parameters(), lr=0.01, momentum=0.9)

model.train()
for epoch in range(5):  # Number of epochs
    for images, labels in dataloader:
        optimizer.zero_grad()
        outputs = model(images)
        loss = criterion(outputs, labels)
        loss.backward()
        optimizer.step()
    print(f'Epoch {epoch+1}, Loss: {loss.item()}')

# Save the fine-tuned model
torch.save(model.state_dict(), 'fine_tuned_resnet18.pth')